export default function ProjectsPage() {
  const [createOpen, setCreateOpen] = useState(false);
  const [viewMode, setViewMode] = useState<"cards" | "compact">("cards");
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState<"updated" | "added" | "name">("updated");
  const [page, setPage] = useState(1);
  const { data, isLoading } = useSWR("projects", () => projectsApi.list(1, 100));
  const items = data?.data ?? [];

  const PAGE_SIZE = 12;
  const filtered = search
    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
    : items;
  const sorted = useMemo(() => {
    const arr = [...filtered];
    switch (sortBy) {
      case "updated":
        return arr.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
      case "added":
        return arr.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
      case "name":
        return arr.sort((a, b) => a.name.localeCompare(b.name));
    }
  }, [filtered, sortBy]);
  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
  const currentPage = Math.min(page, totalPages);
  const paged = sorted.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);

  return (
    <div className="flex flex-col gap-4 fade-in">
      <div className="flex items-center justify-between">
        <div>
          <h1
            style={{
              fontFamily: "var(--font-fraunces)",
              fontSize: "24px",
              fontWeight: 700,
              color: "#111113",
            }}
          >
            Projects
          </h1>
          <p
            className="mt-1 text-[13px] text-[#6b7280]"
            style={{ fontFamily: "var(--font-dm-sans)" }}
          >
            Tracked software projects and their recent releases.
          </p>
        </div>
        <div className="flex items-center gap-2">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5" style={{ color: "#9ca3af" }} />
            <input
              type="text"
              value={search}
              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
              placeholder="Search projects..."
              className="rounded-md border py-1.5 pl-8 pr-3 text-[13px] w-48"
              style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}
            />
          </div>
          <div className="flex items-center gap-1.5 rounded-md border px-2.5 py-1.5 text-[13px]" style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}>
            <ArrowUpDown className="h-3.5 w-3.5 shrink-0" style={{ color: "#9ca3af" }} />
            <select
              value={sortBy}
              onChange={(e) => { setSortBy(e.target.value as "updated" | "added" | "name"); setPage(1); }}
              className="bg-transparent outline-none cursor-pointer text-[13px]"
              style={{ fontFamily: "var(--font-dm-sans)", color: "#374151" }}
            >
              <option value="updated">Recently updated</option>
              <option value="added">Recently added</option>
              <option value="name">Name</option>
            </select>
          </div>
          <div className="flex items-center rounded-md border" style={{ borderColor: "#e8e8e5" }}>
            <button
              onClick={() => setViewMode("cards")}
              className="p-1.5 rounded-l-md transition-colors"
              style={{
                backgroundColor: viewMode === "cards" ? "#f3f3f1" : "transparent",
                color: viewMode === "cards" ? "#111113" : "#9ca3af",
              }}
              title="Card view"
            >
              <LayoutGrid className="h-4 w-4" />
            </button>
            <button
              onClick={() => setViewMode("compact")}
              className="p-1.5 rounded-r-md transition-colors"
              style={{
                backgroundColor: viewMode === "compact" ? "#f3f3f1" : "transparent",
                color: viewMode === "compact" ? "#111113" : "#9ca3af",
              }}
              title="Compact view"
            >
              <List className="h-4 w-4" />
            </button>
          </div>
          <button
            onClick={() => setCreateOpen(true)}
            className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
          >
            <Plus className="h-3.5 w-3.5" />
            New Project
          </button>
        </div>
      </div>

      {isLoading ? (
        <p
          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
          style={{ fontFamily: "var(--font-fraunces)" }}
        >
          Loading...
        </p>
      ) : items.length === 0 ? (
        <div
          className="flex flex-col items-center justify-center rounded-md border py-12"
          style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
        >
          <p
            className="text-[14px] italic text-[#9ca3af]"
            style={{ fontFamily: "var(--font-fraunces)" }}
          >
            No projects yet — create one to start tracking releases
          </p>
          <button
            onClick={() => setCreateOpen(true)}
            className="mt-4 flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
          >
            <Plus className="h-3.5 w-3.5" />
            New Project
          </button>
        </div>
      ) : filtered.length === 0 ? (
        <p
          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
          style={{ fontFamily: "var(--font-fraunces)" }}
        >
          No projects matching &ldquo;{search}&rdquo;
        </p>
      ) : (
        <>
          <div className={viewMode === "cards" ? "space-y-5" : "space-y-1.5"}>
            {paged.map((project) =>
              viewMode === "cards" ? (
                <ProjectFlowCard key={project.id} project={project} />
              ) : (
                <ProjectCompactRow key={project.id} project={project} />
              )
            )}
          </div>
          {totalPages > 1 && (
            <div className="flex items-center justify-center gap-3 pt-2">
              <button
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={currentPage <= 1}
                className="rounded-md border px-3 py-1 text-[13px] transition-colors disabled:opacity-40"
                style={{ borderColor: "#e8e8e5", color: "#374151", fontFamily: "var(--font-dm-sans)" }}
              >
                Previous
              </button>
              <span
                className="text-[13px]"
                style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
              >
                Page {currentPage} of {totalPages}
              </span>
              <button
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={currentPage >= totalPages}
                className="rounded-md border px-3 py-1 text-[13px] transition-colors disabled:opacity-40"
                style={{ borderColor: "#e8e8e5", color: "#374151", fontFamily: "var(--font-dm-sans)" }}
              >
                Next
              </button>
            </div>
          )}
        </>
      )}

      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Create Project</DialogTitle>
          </DialogHeader>
          <ProjectForm
            title="Create Project"
            onSubmit={async (result) => {
              const created = await projectsApi.create(result.project);
              if (result.source && created.data?.id) {
                const res = await sourcesApi.create(created.data.id, result.source);
                if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
              }
            }}
            onSuccess={() => { setCreateOpen(false); mutate("projects"); }}
            onCancel={() => setCreateOpen(false)}
          />
        </DialogContent>
      </Dialog>
    </div>
  );
}

package api

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"strings"
	"time"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"
	"github.com/sentioxyz/changelogue/internal/models"
	"github.com/sentioxyz/changelogue/internal/queue"
)

// PgStore implements all store interfaces using a PostgreSQL connection pool.
type PgStore struct {
	pool  *pgxpool.Pool
	river *river.Client[pgx.Tx]
}

// NewPgStore returns a new PgStore backed by the given connection pool and River client.
// The river client may be nil if agent triggering is not needed.
func NewPgStore(pool *pgxpool.Pool, riverClient *river.Client[pgx.Tx]) *PgStore {
	return &PgStore{pool: pool, river: riverClient}
}

// SetRiverClient updates the River client on an existing PgStore.
// This is used during bootstrap to inject the client after worker registration.
func (s *PgStore) SetRiverClient(rc *river.Client[pgx.Tx]) {
	s.river = rc
}

// --- ProjectsStore ---

func (s *PgStore) ListProjects(ctx context.Context, page, perPage int) ([]models.Project, int, error) {
	var total int
	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&total)
	if err != nil {
		return nil, 0, fmt.Errorf("count projects: %w", err)
	}
	offset := (page - 1) * perPage
	rows, err := s.pool.Query(ctx,
		`SELECT id, name, COALESCE(description,''), COALESCE(agent_prompt,''),
		        COALESCE(agent_rules,'{}'), created_at, updated_at
		 FROM projects ORDER BY created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
	if err != nil {
		return nil, 0, fmt.Errorf("list projects: %w", err)
	}
	defer rows.Close()
	var projects []models.Project
	for rows.Next() {
		var p models.Project
		if err := rows.Scan(&p.ID, &p.Name, &p.Description, &p.AgentPrompt, &p.AgentRules, &p.CreatedAt, &p.UpdatedAt); err != nil {
			return nil, 0, fmt.Errorf("scan project: %w", err)
		}
		projects = append(projects, p)
	}
	return projects, total, nil
}

func (s *PgStore) CreateProject(ctx context.Context, p *models.Project) error {
	return s.pool.QueryRow(ctx,
		`INSERT INTO projects (name, description, agent_prompt, agent_rules)
		 VALUES ($1, $2, $3, $4)
		 RETURNING id, created_at, updated_at`,
		p.Name, p.Description, p.AgentPrompt, p.AgentRules,
	).Scan(&p.ID, &p.CreatedAt, &p.UpdatedAt)
}

func (s *PgStore) GetProject(ctx context.Context, id string) (*models.Project, error) {
	var p models.Project
	err := s.pool.QueryRow(ctx,
		`SELECT id, name, COALESCE(description,''), COALESCE(agent_prompt,''),
		        COALESCE(agent_rules,'{}'), created_at, updated_at
		 FROM projects WHERE id = $1`, id,
	).Scan(&p.ID, &p.Name, &p.Description, &p.AgentPrompt, &p.AgentRules, &p.CreatedAt, &p.UpdatedAt)
	if err != nil {
		return nil, err
	}
	return &p, nil
}

func (s *PgStore) UpdateProject(ctx context.Context, id string, p *models.Project) error {
	return s.pool.QueryRow(ctx,
		`UPDATE projects SET name=$1, description=$2, agent_prompt=$3, agent_rules=$4, updated_at=NOW()
		 WHERE id=$5 RETURNING updated_at`,
		p.Name, p.Description, p.AgentPrompt, p.AgentRules, id,
	).Scan(&p.UpdatedAt)
}

func (s *PgStore) DeleteProject(ctx context.Context, id string) error {
	tag, err := s.pool.Exec(ctx, `DELETE FROM projects WHERE id = $1`, id)
	if err != nil {
		return err
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("not found")
	}
	return nil
}

// --- KeyStore ---

func (s *PgStore) ValidateKey(ctx context.Context, rawKey string) (bool, error) {
	hash := sha256.Sum256([]byte(rawKey))
	keyHash := hex.EncodeToString(hash[:])
	var exists bool
	err := s.pool.QueryRow(ctx,
		`SELECT EXISTS(SELECT 1 FROM api_keys WHERE key_hash = $1)`, keyHash,
	).Scan(&exists)
	return exists, err
}

func (s *PgStore) TouchKeyUsage(ctx context.Context, rawKey string) {
	hash := sha256.Sum256([]byte(rawKey))
	keyHash := hex.EncodeToString(hash[:])
	_, _ = s.pool.Exec(ctx, `UPDATE api_keys SET last_used_at = NOW() WHERE key_hash = $1`, keyHash)
}

// --- SourcesStore ---

func (s *PgStore) ListSourcesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Source, int, error) {
	var total int
	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM sources WHERE project_id = $1`, projectID).Scan(&total)
	if err != nil {
		return nil, 0, fmt.Errorf("count sources: %w", err)
	}
	offset := (page - 1) * perPage
	rows, err := s.pool.Query(ctx,
		`SELECT id, project_id, provider, repository, poll_interval_seconds, enabled,
		        COALESCE(config,'{}'), version_filter_include, version_filter_exclude, exclude_prereleases,
		        last_polled_at, last_error, created_at, updated_at
		 FROM sources WHERE project_id = $1 ORDER BY created_at DESC LIMIT $2 OFFSET $3`, projectID, perPage, offset)
	if err != nil {
		return nil, 0, fmt.Errorf("list sources: %w", err)
	}
	defer rows.Close()
	var sources []models.Source
	for rows.Next() {
		var src models.Source
		if err := rows.Scan(&src.ID, &src.ProjectID, &src.Provider, &src.Repository,
			&src.PollIntervalSeconds, &src.Enabled, &src.Config,
			&src.VersionFilterInclude, &src.VersionFilterExclude, &src.ExcludePrereleases,
			&src.LastPolledAt, &src.LastError, &src.CreatedAt, &src.UpdatedAt); err != nil {
			return nil, 0, fmt.Errorf("scan source: %w", err)
		}
		sources = append(sources, src)
	}
	return sources, total, nil
}

func (s *PgStore) CreateSource(ctx context.Context, src *models.Source) error {
