   503→  const filtered = search
   504→    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
   505→    : items;
   506→  const sorted = useMemo(() => {
   507→    const arr = [...filtered];
   508→    switch (sortBy) {
   509→      case "updated":
   510→        return arr.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
   511→      case "added":
   512→        return arr.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
   513→      case "name":
   514→        return arr.sort((a, b) => a.name.localeCompare(b.name));
   515→    }
   516→  }, [filtered, sortBy]);
   517→  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
   518→  const currentPage = Math.min(page, totalPages);
   519→  const paged = sorted.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);
   520→
   521→  return (
   522→    <div className="flex flex-col gap-4 fade-in">
   523→      <div className="flex items-center justify-between">
