   551→              style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}
   552→            />
   553→          </div>
   554→          <div className="flex items-center gap-1.5 rounded-md border px-2.5 py-1.5 text-[13px]" style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}>
   555→            <ArrowUpDown className="h-3.5 w-3.5 shrink-0" style={{ color: "#9ca3af" }} />
   556→            <select
   557→              value={sortBy}
   558→              onChange={(e) => { setSortBy(e.target.value as "updated" | "added" | "name"); setPage(1); }}
   559→              className="bg-transparent outline-none cursor-pointer text-[13px]"
   560→              style={{ fontFamily: "var(--font-dm-sans)", color: "#374151" }}
   561→            >
   562→              <option value="updated">Recently updated</option>
