   685→              if (result.source && created.data?.id) {
   686→                const res = await sourcesApi.create(created.data.id, result.source);
   687→                if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   688→              }
   689→            }}
   690→            onSuccess={() => { setCreateOpen(false); mutate("projects"); }}
   691→            onCancel={() => setCreateOpen(false)}
   692→          />
   693→        </DialogContent>
